// Read Input — parses LLM intent output with regex fallback
const trigger = $('Execute Workflow Trigger').first().json;
const llmRaw = $input.first().json;

const OWNER_PERSON_ID = 'YOUR_OWNER_PERSON_ID';

// Try to parse LLM JSON output
let parsed = null;
if (!llmRaw.error) {
  try {
    const content = llmRaw.text || llmRaw.output || llmRaw.choices?.[0]?.message?.content || '';
    const jsonStr = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    parsed = JSON.parse(jsonStr);
  } catch(e) {}
}

let action = trigger.action || parsed?.action || null;
let to_address = trigger.action ? trigger.to_address : (parsed?.to_address || null);
let subject = trigger.subject || parsed?.subject || null;
let body_prompt = trigger.body_prompt || parsed?.body_prompt || null;
let search_query = trigger.search_query || parsed?.search_query || null;
let account = trigger.account || parsed?.account || null;
let confirm_draft_id = trigger.confirm_draft_id || parsed?.confirm_draft_id || null;
let source_channel = trigger.source_channel || 'discord';

// Regex fallback if LLM didn't resolve action
if (!action) {
  const q = (trigger.query || '').trim();
  const actionKV = q.match(/\baction:\s*(\w+)/i);
  if (actionKV) {
    action = actionKV[1].toLowerCase();
  } else if (/\bsearch\b/i.test(q) || /\bfind\b/i.test(q) || /\blook\s+for\b/i.test(q)) {
    action = 'search';
    if (!search_query) {
      let cleaned = q.replace(/^\s*(search(\s+for)?|find|look\s+for)\s*/i, '').trim();
      cleaned = cleaned.replace(/^.*?\binbox\s+for\s+/i, '').trim();
      cleaned = cleaned.replace(/^["']|["']$/g, '').trim();
      if (cleaned) search_query = cleaned;
    }
  } else if (/\bsend\b/i.test(q) || /\bcompose\b/i.test(q) || /\bwrite\b/i.test(q)) {
    action = 'send';
  } else if (/\bconfirm\b/i.test(q) || /\byes\s+send\b/i.test(q)) {
    action = 'confirm';
  } else {
    action = 'read';
  }
  if (!to_address) {
    const m = q.match(/\bto:\s*([^\s,]+)/i);
    if (m) to_address = m[1].trim();
  }
  if (!subject) {
    const m = q.match(/\bsubject:\s*(.+?)(?:,\s*(?:body|search_query|action|to):|$)/i);
    if (m) subject = m[1].trim();
  }
  if (!body_prompt) {
    const m = q.match(/\bbody:\s*(.+)$/i);
    if (m) body_prompt = m[1].trim();
  }
}

// Account detection
if (!account) {
  const q = (trigger.query || '').toLowerCase();
  if (/\b(your|aerys)\s*(inbox|email|mail|messages?)\b/.test(q) || /\baerys\s+inbox\b/.test(q)) {
    account = 'aerys';
  } else {
    account = 'user';
  }
}

action = action || 'read';

// person_id: use trigger value if present, fall back to 'unknown' (NOT owner)
// Check Email Auth gates access before this node runs
const person_id = trigger.person_id || 'unknown';

return [{json: {
  action,
  person_id,
  to_address,
  subject,
  body_prompt,
  search_query,
  account,
  confirm_draft_id,
  source_channel
}}];

const resp = $input.first().json;
// chainLlm outputs {text: "..."} — not OpenAI choices format
const emailBody = resp?.text || resp?.output || resp?.choices?.[0]?.message?.content || 'I had trouble drafting that email. Please try again.';
const input = $('Read Input').item.json;
return [{json: {
  email_body: emailBody,
  person_id: input.person_id,
  to_address: input.to_address,
  subject: input.subject || '(no subject)'
}}];

const draft = $('Save Draft').item.json;
const body = $('Parse Email Body').item.json;
const result = `Here's the draft:

**To:** ${body.to_address}
**Subject:** ${body.subject}

${body.email_body}

Reply with "send it" to send, or tell me what to change.`;
return [{json: {result}}];

const account = $('Read Input').first().json.account || 'aerys';
const emails = $input.all().map(i => i.json).filter(e => e.id);
if (emails.length === 0) {
  const msg = account === 'user' ? 'Your inbox is empty — all clear.' : 'My inbox is empty — all clear.';
  return [{json: {result: msg}}];
}
const list = emails.map((e, i) => {
  const from = e.From || e.from || 'unknown';
  const subject = e.Subject || e.subject || '(no subject)';
  const snippet = (e.snippet || '').substring(0, 120);
  return `${i+1}. From: ${from}\n   ${subject}\n   ${snippet}`;
}).join('\n\n');
const header = account === 'user' ? "Here's what's in your inbox:" : "Here's what's in my inbox:";
return [{json: {result: `${header}\n\n${list}`}}];

const input = $('Read Input').item.json;
const emails = $input.all().map(i => i.json).filter(e => e.id);
if (emails.length === 0) {
  return [{json: {result: `Nothing found matching '${input.search_query}'.`}}];
}
const list = emails.map((e, i) => {
  const from = e.From || e.from || 'unknown';
  const subject = e.Subject || e.subject || '(no subject)';
  const snippet = (e.snippet || '').substring(0, 120);
  return `${i+1}. From: ${from}\n   ${subject}\n   ${snippet}`;
}).join('\n\n');
return [{json: {result: `Found ${emails.length} matching '${input.search_query}':\n\n${list}`}}];

return [{json: {
  result: 'EMAIL_ACCESS_DENIED: Email access is restricted to the account owner. Inform the user clearly and directly: you cannot access email for them — this is a permanent restriction, not a temporary issue. Do not suggest trying again or offer workarounds.'
}}];

